def user_to_dict(user):
    return {
        "id": user["id"],
        "username": user["username"],
        "mfa_enabled": bool(user["mfa_enabled"]),
        "created_at": user["created_at"],
    }


def get_user_by_username(username):
    db = get_db()
    return db.execute("SELECT * FROM users WHERE username = ?", (username,)).fetchone()


def get_user_by_id(user_id):
    db = get_db()
    return db.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()


def create_user(username, password, mfa_enabled=False, mfa_secret=None):
    db = get_db()
    password_hash = generate_password_hash(password)
    db.execute(
        """
        INSERT INTO users (username, password_hash, mfa_enabled, mfa_secret, created_at)
        VALUES (?, ?, ?, ?, ?)
        """,
        (
            username,
            password_hash,
            1 if mfa_enabled else 0,
            mfa_secret,
            datetime.utcnow().isoformat(),
        ),
    )
    db.commit()
    return get_user_by_username(username)


def require_json():
    if not request.is_json:
        return jsonify({"error": "Content-Type must be application/json"}), 400
    return None


def login_user_session(user):
    session.clear()
    session["user_id"] = user["id"]
    session["authenticated"] = True
    session["auth_method"] = "password+mfa" if user["mfa_enabled"] else "password"
    session["login_at"] = datetime.utcnow().isoformat()


def set_pending_mfa(user):
    session.clear()
    session["pending_mfa_user_id"] = user["id"]
    session["pending_mfa_expires_at"] = (
        datetime.utcnow() + timedelta(minutes=MFA_SESSION_TTL_MINUTES)
    ).isoformat()


def is_pending_mfa_valid():
    user_id = session.get("pending_mfa_user_id")
    expires_at = session.get("pending_mfa_expires_at")
    if not user_id or not expires_at:
        return False
    try:
        expiry = datetime.fromisoformat(expires_at)
    except ValueError:
        return False
    return datetime.utcnow() <= expiry


def generate_totp_secret():
    if pyotp:
        return pyotp.random_base32()
    return base64.b32encode(secrets.token_bytes(20)).decode("utf-8").rstrip("=")


def verify_totp(secret, otp):
    if not secret or not otp:
        return False
    if pyotp:
        totp = pyotp.TOTP(secret)
        return totp.verify(str(otp), valid_window=1)
    return verify_totp_fallback(secret, otp)


def verify_totp_fallback(secret, otp, interval=30, digits=6, valid_window=1):
    try:
        key = base64.b32decode(secret + "=" * ((8 - len(secret) % 8) % 8), casefold=True)
    except Exception:
        return False

    def hotp(counter):
        msg = counter.to_bytes(8, "big")
        hs = hmac.new(key, msg, hashlib.sha1).digest()
        offset = hs[-1] & 0x0F
        dbc = int.from_bytes(hs[offset:offset + 4], "big") & 0x7FFFFFFF
        return str(dbc % (10 ** digits)).zfill(digits)

    current_counter = int(datetime.utcnow().timestamp() // interval)
    otp = str(otp).strip()
    for offset in range(-valid_window, valid_window + 1):
        if secrets.compare_digest(hotp(current_counter + offset), otp):
            return True
    return False


def auth_required():
    return bool(session.get("authenticated") and session.get("user_id"))


@app.route("/api/register", methods=["POST"])
def register():
    err = require_json()
    if err:
        return err

    data = request.get_json()
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    mfa_enabled = bool(data.get("mfa_enabled", False))

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    if get_user_by_username(username):
        return jsonify({"error": "username already exists"}), 409

    mfa_secret = generate_totp_secret() if mfa_enabled else None
    user = create_user(username, password, mfa_enabled=mfa_enabled, mfa_secret=mfa_secret)

    response = {"message": "user created", "user": user_to_dict(user)}
    if mfa_enabled:
        response["mfa_secret"] = mfa_secret
    return jsonify(response), 201


@app.route("/api/login", methods=["POST"])
def login():
    err = require_json()
    if err:
        return err

    data = request.get_json()
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    user = get_user_by_username(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "invalid credentials"}), 401

    if user["mfa_enabled"]:
        set_pending_mfa(user)
        return jsonify(
            {
                "message": "password verified, OTP required",
                "mfa_required": True,
                "next": "/api/verify-otp",
            }
        ), 200

    login_user_session(user)
    return jsonify(
        {
            "message": "login successful",
            "mfa_required": False,
            "user": user_to_dict(user),
        }
    ), 200


